import{_ as r,o as t,c as p,j as e,a as n,a1 as s}from"./chunks/framework.Bp7r_-XI.js";const f=JSON.parse('{"title":"海中雷电","description":"","frontmatter":{},"headers":[],"relativePath":"4.资源分区/7.物品与装备/2.武器/近战武器/3.B级/海中雷电.md","filePath":"4.资源分区/7.物品与装备/2.武器/近战武器/3.B级/海中雷电.md"}'),o={name:"4.资源分区/7.物品与装备/2.武器/近战武器/3.B级/海中雷电.md"};function d(l,a,_,i,c,h){return t(),p("div",null,[...a[0]||(a[0]=[e("h1",{id:"海中雷电",tabindex:"-1"},[n("海中雷电 "),e("a",{class:"header-anchor",href:"#海中雷电","aria-label":'Permalink to "海中雷电"'},"​")],-1),e("table",{class:"bannerparthead"},[e("tbody",null,[e("tr",{id:"hdr"},[e("td",{class:"runninghead",nowrap:""},"TMD：汹涌疾风029特别节愚人版")])])],-1),s('<h1 id="海中雷电-1" tabindex="-1">海中雷电 <a class="header-anchor" href="#海中雷电-1" aria-label="Permalink to &quot;海中雷电&quot;">​</a></h1><p>海中雷电</p><p>B+2000</p><p>我曾见过天空厌弃之地，那里的雷电永不停息，<br> 此乃其根茎与鲜血，其枝叶与灵魂。</p><p>特殊的，这把武器需要使用电鳗进行换购，在使用电鳗进行三场影片之后，可以使用标注的支线换购海中雷电。</p><p>这把武器在电鳗的基础上，武器伤害上升至18L，具有【轻灵】。</p><p>从正面看去，这仅是一条普通的电鳗，若是从侧面看去，这是一段闪电，而若是从另外一个角度看去，这是一把长矛，不管如何，他依旧使用鞭作为专业。</p><p>反叛者：<br> “你手中的闪电可不是孤品，持矛者，<br> 大海将与天空同级。”</p><p>这把武器将造成雷击伤害，并且其触及范围扩大20M，在你使用它进行攻击时，会附带等量的麻痹异常点数，正常豁免，同时受击者需要以反射豁免对抗出目，否则陷入B级环境来源的【潮湿】效果中，持续一场景。</p><hr><p>Copyright ? 2025 <a href="http://www.goddessfantasy.net/bbs/index.php?board=2008.0" target="_blank" rel="noreferrer">TMDtrpg制作组</a>. All Rights Reserved.</p>',11)])])}const m=r(o,[["render",d]]);export{f as __pageData,m as default};
